#include <algorithm>
using namespace std;

long long solve(std::string s) {
    int n = s.length();
    if (n == 0) return 0;
    vector<int> L_before(n+1, 0);
    vector<int> C_before(n+1, 0);
    vector<int> T_after(n, 0);
    // Compute L_before and C_before
    for (int i = 0; i < n; ++i) {
        L_before[i+1] = L_before[i] + (s[i] == 'L' ? 1 : 0);
        C_before[i+1] = C_before[i] + (s[i] == 'C' ? 1 : 0);
    }
    // Compute T_after
    int t_count = 0;
    for (int i = n-1; i >= 0; --i) {
        T_after[i] = t_count;
        if (s[i] == 'T') {
            t_count++;
        }
    }
    // Compute sum_T_after_C
    vector<int> sum_T_after_C(n+1, 0);
    for (int i = n-1; i >= 0; --i) {
        if (s[i] == 'C') {
            sum_T_after_C[i] = T_after[i] + sum_T_after_C[i+1];
        } else {
            sum_T_after_C[i] = sum_T_after_C[i+1];
        }
    }
    // Compute original count
    long long original = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'C') {
            original += (long long)L_before[i] * T_after[i];
        }
    }
    // Compute max_L
    long long max_L = 0;
    for (int i = 0; i <= n; ++i) {
        max_L = max(max_L, (long long)sum_T_after_C[i]);
    }
    // Compute max_C
    long long max_C = 0;
    for (int i = 0; i <= n; ++i) {
        long long val = (long long)L_before[i] * T_after[i];
        max_C = max(max_C, val);
    }
    // Compute max_T
    long long max_T = 0;
    for (int i = 0; i <= n; ++i) {
        long long val = (long long)L_before[i] * C_before[i];
        max_T = max(max_T, val);
    }
    // Final answer
    return original + max(max_L, max_C, max_T);
}

