```typescript
function solve(s: string): number {
    const n = s.length;
    if (n === 0) return 0;

    const L_before = new Array(n + 1).fill(0);
    const C_before = new Array(n + 1).fill(0);

    for (let i = 0; i < n; i++) {
        L_before[i + 1] = L_before[i] + (s[i] === 'L' ? 1 : 0);
        C_before[i + 1] = C_before[i] + (s[i] === 'C' ? 1 : 0);
    }

    const T_after = new Array(n).fill(0);
    let t_count = 0;
    for (let i = n - 1; i >= 0; i--) {
        T_after[i] = t_count;
        if (s[i] === 'T') {
            t_count++;
        }
    }

    const sum_T_after_C = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        if (s[i] === 'C') {
            sum_T_after_C[i] = T_after[i] + sum_T_after_C[i + 1];
        } else {
            sum_T_after_C[i] = sum_T_after_C[i + 1];
        }
    }

    let original = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'C') {
            original += L_before[i] * T_after[i];
        }
    }

    let max_L = 0;
    for (let i = 0; i <= n; i++) {
        max_L = Math.max(max_L, sum_T_after_C[i]);
    }

    let max_C = 0;
    for (let i = 0; i <= n; i++) {
        const t = i < n ? T_after[i] : 0;
        max_C = Math.max(max_C, L_before[i] * t);
    }

    let max_T = 0;
    for (let i = 0; i <= n; i++) {
        max_T = Math.max(max_T, L_before[i] * C_before[i]);
    }

    return original + Math.max(max_L, max_C, max_T);
}
